package basics_01;

public class Mathfun {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		double result;
		result=Math.pow(2,4);
		System.out.println(result);
		result=Math.sqrt(4);
	System.out.println(result);
	result=Math.abs(-6);
	System.out.println(result);
	result=Math.max(23,4);
	System.out.println(result);
	result=Math.min(2,4);
	System.out.println(result);
	result=Math.ceil(3.24);
	System.out.println(result);
	result=Math.floor(3.56);
	System.out.println(result);
	
	

	}

}
